import{_ as s,a as r}from"./chunks/Pinia_full_screen.CrXGkRZm.js";import{_ as a,c as n,o as e,ag as o}from"./chunks/framework.Dnsuz9ka.js";const b=JSON.parse('{"title":"Работа с Pinia Stores","description":"","frontmatter":{"title":"Работа с Pinia Stores"},"headers":[],"relativePath":"ru/store/general.md","filePath":"ru/store/general.md"}'),i={name:"ru/store/general.md"};function l(g,t,h,d,p,k){return e(),n("div",null,[...t[0]||(t[0]=[o('<h1 id="работа-с-pinia-stores" tabindex="-1">Работа с Pinia Stores <a class="header-anchor" href="#работа-с-pinia-stores" aria-label="Permalink to &quot;Работа с Pinia Stores&quot;">​</a></h1><p>Раздел <strong>Stores</strong> предназначен для просмотра зарегистрированных в приложении <strong>Pinia</strong>-сторов: имя (идентификатор), число полей <strong>state</strong> и <strong>getters</strong>, а после выбора строки — снимок <strong>state</strong> и <strong>getters</strong> с возможностью правок и записи обратно в приложение (в поддерживаемых случаях).</p><p>Подробнее про редактирование <strong>state</strong> и <strong>getters</strong>, а также про <strong>избранное</strong> по сторам:</p><ul><li><a href="/qa-tools/docs/ru/store/state.html">Работа со State</a></li><li><a href="/qa-tools/docs/ru/store/getters.html">Работа с Getters</a></li><li><a href="/qa-tools/docs/ru/store/favorite.html">Избранное</a></li></ul><h2 id="верхняя-панель-управления" tabindex="-1">Верхняя панель управления <a class="header-anchor" href="#верхняя-панель-управления" aria-label="Permalink to &quot;Верхняя панель управления&quot;">​</a></h2><p><img src="'+s+'" alt="Store, область заголовка"></p><h3 id="поиск-по-сторам" tabindex="-1">Поиск по сторам <a class="header-anchor" href="#поиск-по-сторам" aria-label="Permalink to &quot;Поиск по сторам&quot;">​</a></h3><p>Поле поиска и переключатель <strong>Search by</strong> работают так же, как и в других вкладках. Типы поиска можно заранее задать в <strong>Options</strong> для вкладки <strong>Stores</strong>.</p><table tabindex="0"><thead><tr><th>Режим</th><th>Назначение</th></tr></thead><tbody><tr><td><strong>Name</strong></td><td>фильтр по имени стора (локально в панели)</td></tr><tr><td><strong>Key</strong></td><td>совпадение по именам полей в <strong>state</strong> и <strong>getters</strong> (поиск на стороне страницы)</td></tr><tr><td><strong>Value</strong></td><td>совпадение по значениям в <strong>state</strong> и <strong>getters</strong> (также на стороне страницы)</td></tr></tbody></table><p>Для <strong>Key</strong> и <strong>Value</strong> действует минимальная длина запроса (по умолчанию <strong>2</strong> символа; настраивается в параметрах поиска инспектора).</p><p><strong>Частичное и точное совпадение.</strong> Если запрос <strong>не</strong> обёрнут в кавычки, используется <strong>подстрока</strong> (без учёта регистра). <strong>Точное</strong> совпадение включается, если <strong>весь</strong> запрос обёрнут в <strong>двойные кавычки</strong> <code>&quot;...&quot;</code>.</p><p>На стороне поиска по содержимому действует ограничение числа результатов, чтобы не перегружать страницу при широком запросе.</p><h3 id="индикаторы-состояния" tabindex="-1">Индикаторы состояния <a class="header-anchor" href="#индикаторы-состояния" aria-label="Permalink to &quot;Индикаторы состояния&quot;">​</a></h3><p>Справа на панели <strong>Stores</strong> отображаются:</p><table tabindex="0"><thead><tr><th>Элемент</th><th>Назначение</th></tr></thead><tbody><tr><td><strong>N</strong> или <strong>N/M</strong></td><td>Число сторов после фильтра; при непустом поиске через дробь — общее число сторов в последней сводке.</td></tr><tr><td><strong>Избранное</strong> ★</td><td>Совпадения с избранными сторами. Клик открывает <strong>Options</strong> (раздел избранного Pinia).</td></tr><tr><td><strong>Обновление</strong></td><td>Кнопка <strong>Refresh</strong>, индикатор загрузки и время последней успешной сводки (или текст вида <code>Loading...</code>).</td></tr></tbody></table><p>Перед запросом сводки панель проверяет доступность канала связи со страницей; если контекст недоступен, данные не запрашиваются.</p><h2 id="рабочая-область" tabindex="-1">Рабочая область <a class="header-anchor" href="#рабочая-область" aria-label="Permalink to &quot;Рабочая область&quot;">​</a></h2><p><img src="'+r+`" alt="Pinia, полноэкранный режим"></p><h3 id="список-сторов" tabindex="-1">Список сторов <a class="header-anchor" href="#список-сторов" aria-label="Permalink to &quot;Список сторов&quot;">​</a></h3><p>Слева отображается таблица сторов. Основные колонки (видимость задаётся в настройках таблицы):</p><ul><li><strong>Name</strong> — отображаемое имя стора (<strong>baseId</strong>);</li><li><strong>State</strong> — число ключей в state (если нет — прочерк);</li><li><strong>Getters</strong> — число getters (если нет — прочерк).</li></ul><p>У строки доступны <strong>звезда избранного</strong> и контекстное меню. Избранное хранится в настройках инспектора; см. <a href="/qa-tools/docs/ru/store/favorite.html">Избранное</a>.</p><h2 id="детализация-стора" tabindex="-1">Детализация стора <a class="header-anchor" href="#детализация-стора" aria-label="Permalink to &quot;Детализация стора&quot;">​</a></h2><p>При выборе строки элемента открывается панель детализации выбранного стора.</p><h3 id="сводная-информация" tabindex="-1">Сводная информация <a class="header-anchor" href="#сводная-информация" aria-label="Permalink to &quot;Сводная информация&quot;">​</a></h3><p>В верхней части панели отображаются:</p><ul><li>имя стора;</li><li>число ключей <strong>State</strong>;</li><li>число ключей <strong>Getters</strong>;</li><li>строка <strong>Updated:</strong> с меткой времени последнего обновления данных карточки.</li></ul><h3 id="данные-стора" tabindex="-1">Данные стора <a class="header-anchor" href="#данные-стора" aria-label="Permalink to &quot;Данные стора&quot;">​</a></h3><p>Ниже доступны вкладки:</p><table tabindex="0"><thead><tr><th>Вкладка</th><th>Назначение</th></tr></thead><tbody><tr><td><strong>State</strong></td><td>снимок реактивного <strong>state</strong>; поддерживаются просмотр и сохранение изменений</td></tr><tr><td><strong>Getters</strong></td><td>снимок текущих значений <strong>getters</strong> в сериализованном виде; поддерживается просмотр и ограниченное редактирование</td></tr></tbody></table><p>Показываются только те вкладки, для которых доступны данные.</p><p>Данные активной вкладки отображаются в формате <strong>JSON</strong> — в текстовом или древовидном виде в зависимости от настроек инспектора.</p><h3 id="навигация" tabindex="-1">Навигация <a class="header-anchor" href="#навигация" aria-label="Permalink to &quot;Навигация&quot;">​</a></h3><ul><li>кнопка <strong>← Назад</strong> закрывает детализацию и возвращает к таблице;</li><li><strong>Esc</strong> в режиме редактирования отменяет изменения;</li><li><strong>Esc</strong> вне режима редактирования выполняет возврат к списку.</li></ul><h3 id="элементы-управления" tabindex="-1">Элементы управления <a class="header-anchor" href="#элементы-управления" aria-label="Permalink to &quot;Элементы управления&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Элемент</th><th>Назначение</th></tr></thead><tbody><tr><td><strong>Star</strong></td><td>добавить или убрать стор из избранного</td></tr><tr><td><strong>Refresh</strong></td><td>повторно запросить данные выбранного стора с страницы; доступна вне режима <strong>Edit</strong></td></tr><tr><td><strong>Edit</strong></td><td>перейти в режим редактирования активной вкладки (<strong>State</strong> или <strong>Getters</strong>)</td></tr></tbody></table><h3 id="режим-редактирования" tabindex="-1">Режим редактирования <a class="header-anchor" href="#режим-редактирования" aria-label="Permalink to &quot;Режим редактирования&quot;">​</a></h3><p>После включения режима <strong>Edit</strong> кнопки <strong>Refresh</strong> и <strong>Edit</strong> заменяются на <strong>Cancel</strong> и <strong>Save</strong>.</p><table tabindex="0"><thead><tr><th>До редактирования</th><th>В режиме редактирования</th></tr></thead><tbody><tr><td><strong>Refresh</strong></td><td><strong>Cancel</strong> — отмена изменений и выход из режима редактирования</td></tr><tr><td><strong>Edit</strong></td><td><strong>Save</strong> — применить изменения в приложение</td></tr></tbody></table><p>Изменения попадают в приложение только после подтверждения через <strong>Save</strong>.</p><p>Для <strong>State</strong> используется обновление текущего состояния стора, для <strong>Getters</strong> — запись поддерживается только в допустимых сценариях; ограничения зависят от реализации конкретного стора.</p><p>Звезда <strong>избранного</strong> в этой панели и в таблице описана на странице <a href="/qa-tools/docs/ru/store/favorite.html">Избранное</a>.</p><p>Данные карточки соответствуют <strong>снимку на момент последнего запроса</strong>: внешние изменения в приложении не отражаются автоматически, пока вы не выполните <strong>Refresh</strong> в карточке или не обновите сводку на верхней панели вкладки <strong>Stores</strong>.</p><h2 id="ограничения-отображения" tabindex="-1">Ограничения отображения <a class="header-anchor" href="#ограничения-отображения" aria-label="Permalink to &quot;Ограничения отображения&quot;">​</a></h2><h3 id="ограничения-чтения-данных" tabindex="-1">Ограничения чтения данных <a class="header-anchor" href="#ограничения-чтения-данных" aria-label="Permalink to &quot;Ограничения чтения данных&quot;">​</a></h3><ol><li><strong>Сводка по всем сторам</strong> — лёгкий ответ: для каждого стора передаются идентификатор, имя, счётчики ключей <strong>state</strong> / <strong>getters</strong> и метка времени снимка, без полной сериализации значений.</li><li><strong>Карточка выбранного стора</strong> — отдельный запрос с сериализованными <strong>state</strong> и <strong>getters</strong> для отображения и редактирования.</li></ol><p>Сериализация <strong>state</strong> и <strong>getters</strong> ограничена разумными пределами глубины и размера: циклические структуры, функции и специальные объекты могут быть усечены или представлены иначе, чем в исходном runtime.</p><p>Результаты поиска по <strong>Key</strong> и <strong>Value</strong> также намеренно ограничены по количеству.</p><h3 id="ограничение-объема-хранения" tabindex="-1">Ограничение объёма хранения <a class="header-anchor" href="#ограничение-объема-хранения" aria-label="Permalink to &quot;Ограничение объёма хранения&quot;">​</a></h3><p>Фиксированного лимита числа сторов в таблице нет: отображаются все сторы, возвращённые сводкой <strong>Pinia</strong> в типичном сценарии.</p><p>Нестандартные регистрации или крайние конфигурации могут отображаться неполно; возможность записи зависит от реализации стора — при ошибке сохранения ориентируйтесь на сообщение интерфейса или консоль.</p><h2 id="принципы-работы" tabindex="-1">Принципы работы <a class="header-anchor" href="#принципы-работы" aria-label="Permalink to &quot;Принципы работы&quot;">​</a></h2><h3 id="когда-начинается-сбор-данных" tabindex="-1">Когда начинается сбор данных <a class="header-anchor" href="#когда-начинается-сбор-данных" aria-label="Permalink to &quot;Когда начинается сбор данных&quot;">​</a></h3><p>Модуль Pinia во внедрённом сценарии подключается после обнаружения <strong>Pinia</strong> на странице (логика сходна с вкладкой <strong>Props</strong>: сначала должны быть Vue и активный инспектор).</p><p>Если Pinia не установлена или ещё не инициализирована при открытии вкладки <strong>Stores</strong>, список будет пустым или появится сообщение об ошибке загрузки.</p><h3 id="что-попадает-в-мониторинг" tabindex="-1">Что попадает в мониторинг <a class="header-anchor" href="#что-попадает-в-мониторинг" aria-label="Permalink to &quot;Что попадает в мониторинг&quot;">​</a></h3><ol><li><strong>Сводка</strong> — только идентификаторы, имена и счётчики полей для таблицы.</li><li><strong>Детали одного стора</strong> — полный сериализованный <strong>state</strong> и <strong>getters</strong> по выбору пользователя.</li></ol><p>Так отделяется <strong>быстрый список</strong> от <strong>тяжёлого чтения</strong> одного стора.</p><h3 id="как-устроен-обмен" tabindex="-1">Как устроен обмен <a class="header-anchor" href="#как-устроен-обмен" aria-label="Permalink to &quot;Как устроен обмен&quot;">​</a></h3><p>Панель не читает Pinia напрямую: она отправляет сообщение в контекст страницы, где доступен реестр зарегистрированных сторов.</p><div class="language-js vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Иллюстрация: запрос сводки — только id стора, имя и счётчики ключей</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> response</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> await</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> bridge.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">send</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">({ type: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;PINIA_GET_STORES_SUMMARY&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> })</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// response.summary — объект «storeId → { id, baseId, stateKeys, getterKeys, … }»</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> detail</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> await</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> bridge.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">send</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">({</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  type: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;PINIA_GET_STORE_STATE&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  storeId: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;my-store-id&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">})</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// detail.state, detail.getters — данные для отображения и редактирования</span></span></code></pre></div><p>Поиск по ключам и значениям (<code>PINIA_SEARCH</code>) выполняется на странице и возвращает только список идентификаторов подходящих сторов.</p><h2 id="см-также" tabindex="-1">См. также <a class="header-anchor" href="#см-также" aria-label="Permalink to &quot;См. также&quot;">​</a></h2><ul><li><a href="/qa-tools/docs/ru/store/state.html">Работа со State</a></li><li><a href="/qa-tools/docs/ru/store/getters.html">Работа с Getters</a></li><li><a href="/qa-tools/docs/ru/store/favorite.html">Избранное</a></li><li><a href="/qa-tools/docs/ru/options/update_settings.html">Параметры обновления и автообновление</a></li></ul>`,64)])])}const E=a(i,[["render",l]]);export{b as __pageData,E as default};
